  ('dietitian-moex-06442', 'dietitian', 'dietitian-moex-105-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '一份學童午餐熱量630大卡，蛋白質提供約15%熱量，菜單已先設計有青江菜1份、雪裡紅0.5份、 蘋果1份、白飯4.5份之外，則午餐應該再設計幾份的豆魚肉蛋類食物？', '["1.5", "2", "2.5", "3"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:44+00:00", "source_pdf_sha1": "1cb0f1fd964e", "answer_pdf_sha1": "5ab5d8c44f1c", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
